/**
 * Updates the Razeco Performance Dashboard with the latest data
 */
function main() {
  // Spreadsheet ID für das Dashboard
  var spreadsheetId = '19s3l4JgQz5U6jw3lgvO9LHlKGvDdzQPpEKMeteqnUqY';
  var ss = SpreadsheetApp.openById(spreadsheetId);

  // Holen Sie das aktuelle Datum und den vorherigen Monat
  var now = new Date();
  var previousMonth = new Date();
  previousMonth.setMonth(previousMonth.getMonth() - 1);

  var monthNames = ['Januar', 'Februar', 'März', 'April', 'Mai', 'Juni',
                    'Juli', 'August', 'September', 'Oktober', 'November', 'Dezember'];
  var previousMonthName = monthNames[previousMonth.getMonth()];

  // Update des Zeitstempels im Dashboard
  var dashboardSheet = ss.getSheetByName('Dashboard');
  dashboardSheet.getRange('B2').setValue(now).setNumberFormat('dd.MM.yyyy');

  // Update des Zeitplans
  var scheduleSheet = ss.getSheetByName('Update Schedule');
  var lastRow = scheduleSheet.getLastRow();

  for (var i = 2; i <= lastRow; i++) {
    scheduleSheet.getRange(i, 2).setValue(now); // Letzte Aktualisierung

    // Nächste Aktualisierung auf den ersten Tag des nächsten Monats setzen
    var nextMonth = new Date();
    nextMonth.setMonth(nextMonth.getMonth() + 1);
    nextMonth.setDate(1); // Erster Tag des nächsten Monats
    scheduleSheet.getRange(i, 3).setValue(nextMonth);
  }

  // In einer echten Implementierung würden hier API-Aufrufe an Werbe-Plattformen erfolgen,
  // um die Daten des Vormonats abzurufen

  // Hier simulieren wir Beispieldaten für die Demonstration
  addSampleData(ss, previousMonthName);

  return { success: true, message: "Dashboard aktualisiert für " + previousMonthName };
}

/**
 * Fügt Beispieldaten für den angegebenen Monat hinzu
 */
function addSampleData(ss, month) {
  var creativesSheet = ss.getSheetByName('Creatives KPIs');
  var adSetsSheet = ss.getSheetByName('Ad Sets KPIs');

  // Bestehende Daten für diesen Monat löschen (falls vorhanden)
  clearExistingData(creativesSheet, month);
  clearExistingData(adSetsSheet, month);

  // Beispieldaten für Creatives
  var creativesData = [
    [month, 'Facebook', 'Sommer-Sale', 'CR001', 'Hautpflege-Video', '9:16', 125000, 3200, 0.0256, 0.45, 1440, 52, 27.69, 3.2, 4608],
    [month, 'Facebook', 'Sommer-Sale', 'CR002', 'Produktvorstellung', '1:1', 98000, 2100, 0.0214, 0.51, 1071, 38, 28.18, 2.8, 2999],
    [month, 'Instagram', 'Neukunden', 'CR003', 'Testimonial Sarah', '4:5', 156000, 4800, 0.0308, 0.38, 1824, 63, 28.95, 3.5, 6384],
    [month, 'Google', 'Remarketing', 'CR004', 'Rabatt-Banner', '16:9', 45000, 980, 0.0218, 0.65, 637, 22, 28.95, 2.9, 1847],
    [month, 'TikTok', 'Brand-Awareness', 'CR005', 'Challenge-Video', '9:16', 210000, 5400, 0.0257, 0.42, 2268, 41, 55.32, 1.9, 4309]
  ];

  // Beispieldaten für Ad Sets
  var adSetsData = [
    [month, 'Facebook', 'Sommer-Sale', 'AS001', 'Lookalike 1%', 'Lookalike Audience', 30, 110000, 2800, 0.0255, 0.47, 1316, 45, 29.24, 3.1, 4080],
    [month, 'Facebook', 'Sommer-Sale', 'AS002', 'Interesse Beauty', 'Interessen-Targeting', 25, 113000, 2500, 0.0221, 0.49, 1225, 45, 27.22, 2.9, 3553],
    [month, 'Instagram', 'Neukunden', 'AS003', 'Frauen 25-34', 'Demografisch', 40, 156000, 4800, 0.0308, 0.38, 1824, 63, 28.95, 3.5, 6384],
    [month, 'Google', 'Remarketing', 'AS004', 'Website-Besucher', 'Remarketing', 20, 45000, 980, 0.0218, 0.65, 637, 22, 28.95, 2.9, 1847],
    [month, 'TikTok', 'Brand-Awareness', 'AS005', 'Ähnliche Zielgruppe', 'Lookalike', 35, 210000, 5400, 0.0257, 0.42, 2268, 41, 55.32, 1.9, 4309]
  ];

  // Daten in die Tabelle einfügen
  var nextCreativesRow = getNextEmptyRow(creativesSheet);
  creativesSheet.getRange(nextCreativesRow, 1, creativesData.length, creativesData[0].length).setValues(creativesData);

  var nextAdSetsRow = getNextEmptyRow(adSetsSheet);
  adSetsSheet.getRange(nextAdSetsRow, 1, adSetsData.length, adSetsData[0].length).setValues(adSetsData);
}

/**
 * Bestehende Daten für einen bestimmten Monat löschen
 */
function clearExistingData(sheet, month) {
  var lastRow = sheet.getLastRow();
  if (lastRow <= 1) return; // Nur Header-Zeile

  var dataRange = sheet.getRange(2, 1, lastRow - 1, 1);
  var values = dataRange.getValues();

  var rowsToDelete = [];
  for (var i = 0; i < values.length; i++) {
    if (values[i][0] === month) {
      rowsToDelete.push(i + 2); // +2 wegen 0-basiertem Index und Header-Zeile
    }
  }

  // Zeilen von unten nach oben löschen, um Verschiebungsprobleme zu vermeiden
  for (var j = rowsToDelete.length - 1; j >= 0; j--) {
    sheet.deleteRow(rowsToDelete[j]);
  }
}

/**
 * Findet die nächste leere Zeile in einem Tabellenblatt
 */
function getNextEmptyRow(sheet) {
  var values = sheet.getDataRange().getValues();

  for (var i = 0; i < values.length; i++) {
    var row = values[i];
    var isEmpty = true;

    for (var j = 0; j < row.length; j++) {
      if (row[j] !== '') {
        isEmpty = false;
        break;
      }
    }

    if (isEmpty) {
      return i + 1; // 1-basierter Index
    }
  }

  return values.length + 1; // Nach der letzten Zeile
}

// Aufruf der Hauptfunktion
main();
